const payload = JSON.parse($input.item.json.message);
const after = payload.after || {};

const isBird = after.label === 'bird';
const isVogelbad = after.camera === 'vogelbad';
const isEndOrSnapshot = payload.type === 'end' && after.has_snapshot === true;

if (!isBird || !isVogelbad || !isEndOrSnapshot) {
  return [];
}

return [{
  json: {
    event_id: after.id,
    camera: after.camera,
    label: after.label,
    score: after.top_score,
    start_time: after.start_time,
    end_time: after.end_time
  }
}];

const base64 = $input.item.binary.data.data;
return [{
  json: {
    ...$input.item.json,
    image_base64: base64
  },
  binary: $input.item.binary
}];

const raw = $input.item.json.response;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { umgangssprachlich: 'Parse-Fehler', lateinisch: '', konfidenz: 0, ist_vogel: false, anmerkung: String(raw).slice(0,200) };
}

return [{
  json: {
    event_id: $node['Filter: neues Vogel-Event mit Snapshot'].json.event_id,
    umgangssprachlich: parsed.umgangssprachlich || 'unbekannt',
    lateinisch: parsed.lateinisch || '',
    konfidenz: parsed.konfidenz ?? 0,
    ist_vogel: parsed.ist_vogel ?? true,
    anmerkung: parsed.anmerkung || '',
    zeitstempel: new Date().toISOString(),
    bild_url: `http://<frigate-host>:5000/api/events/${$node['Filter: neues Vogel-Event mit Snapshot'].json.event_id}/snapshot.jpg`
  }
}];
